import React, { useState } from "react";
import '../../styles.css';  // Esta es la ruta correcta para acceder a style.css desde components/admin

export default function AddZapatilla() {
  const [nombre, setNombre] = useState("");
  const [marca, setMarca] = useState("");
  const [precio, setPrecio] = useState(0);
  const [cantidad, setCantidad] = useState(0);
  const [talle, setTalle] = useState("");
  const [categoria, setCategoria] = useState("");  // Nuevo estado para categoría
  const [descripcion, setDescripcion] = useState("");  // Nuevo estado para descripción

  const handleSubmit = async (e) => {
    e.preventDefault();

    const nuevaZapatilla = {
      nombre,
      marca,
      precio,
      cantidad,
      talle,
      categoria,  // Se añade la categoría
      descripcion,  // Se añade la descripción
    };

    try {
      const res = await fetch("http://localhost:8080/zapatillas", {
        method: "POST",
        headers: {
          "Content-Type": "application/json",
        },
        body: JSON.stringify(nuevaZapatilla),
      });

      if (res.ok) {
        alert("Zapatilla guardada con éxito");
        setNombre("");
        setMarca("");
        setPrecio(0);
        setCantidad(0);
        setTalle("");
        setCategoria("");  // Limpiar el campo categoría
        setDescripcion("");  // Limpiar el campo descripción
      } else {
        alert("Error al guardar zapatilla");
      }
    } catch (error) {
      console.error("Error:", error);
      alert("Error de red al guardar zapatilla");
    }
  };

  return (
    <div className="form-container">
      <h2 className="title">Agregar nueva zapatilla</h2>
      <form onSubmit={handleSubmit} className="form">
        <div className="input-group">
          <label className="label" htmlFor="nombre">Nombre</label>
          <input
            id="nombre"
            type="text"
            placeholder="Nombre"
            value={nombre}
            onChange={(e) => setNombre(e.target.value)}
            className="input"
            required
          />
        </div>

        <div className="input-group">
          <label className="label" htmlFor="marca">Marca</label>
          <input
            id="marca"
            type="text"
            placeholder="Marca"
            value={marca}
            onChange={(e) => setMarca(e.target.value)}
            className="input"
            required
          />
        </div>

        <div className="input-group">
          <label className="label" htmlFor="precio">Precio</label>
          <input
            id="precio"
            type="number"
            placeholder="Precio"
            value={precio}
            onChange={(e) => setPrecio(Number(e.target.value))}
            className="input"
            required
          />
        </div>

        <div className="input-group">
          <label className="label" htmlFor="cantidad">Cantidad</label>
          <input
            id="cantidad"
            type="number"
            placeholder="Cantidad"
            value={cantidad}
            onChange={(e) => setCantidad(Number(e.target.value))}
            className="input"
            required
          />
        </div>

        <div className="input-group">
          <label className="label" htmlFor="talle">Talle</label>
          <input
            id="talle"
            type="text"
            placeholder="Talle"
            value={talle}
            onChange={(e) => setTalle(e.target.value)}
            className="input"
            required
          />
        </div>

        {/* Nuevo campo para la categoría */}
        <div className="input-group">
          <label className="label" htmlFor="categoria">Categoría</label>
          <input
            id="categoria"
            type="text"
            placeholder="Categoría"
            value={categoria}
            onChange={(e) => setCategoria(e.target.value)}
            className="input"
            required
          />
        </div>

        {/* Nuevo campo para la descripción */}
        <div className="input-group">
          <label className="label" htmlFor="descripcion">Descripción</label>
          <textarea
            id="descripcion"
            placeholder="Descripción"
            value={descripcion}
            onChange={(e) => setDescripcion(e.target.value)}
            className="input"
            required
          />
        </div>

        <button type="submit" className="submit-button">
          Guardar
        </button>
      </form>
    </div>
  );
}
